export function nextGeneration(grid: boolean[][]): boolean[][] {
  if (grid.length === 0) return [];                              // conditional(1) + binding(1) + constant(1) + constant(1)

  const rows = grid.length;                                     // assignment(6) + binding(1) + binding(1)
  const cols = grid[0].length;                                  // assignment(6) + binding(1) + constant(1) + binding(1) + binding(1)

  const countNeighbors = (r: number, c: number): number => {   // assignment(6) + binding(1) + binding(1) + binding(1)
    let count = 0;                                              // assignment(6) + binding(1) + constant(1)
    for (let dr = -1; dr <= 1; dr++) {                         // loop(5) + assignment(6) + binding(1) + constant(1) + binding(1) + constant(1) + assignment(6)
      for (let dc = -1; dc <= 1; dc++) {                       // loop(5) + assignment(6) + binding(1) + constant(1) + binding(1) + constant(1) + assignment(6)
        if (dr === 0 && dc === 0) continue;                    // conditional(4) + binding(1) + constant(1) + binding(1) + constant(1)
        const nr = r + dr;                                     // assignment(6) + binding(1) + binding(1) + binding(1)  [+ is invocation? No, arithmetic op]
        const nc = c + dc;                                     // assignment(6) + binding(1) + binding(1) + binding(1)
        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc]) {  // conditional(4) + bindings(7) + constants(2)
          count++;                                             // assignment(6) + binding(1)
        }
      }
    }
    return count;                                              // binding(1)
  };

  const next = grid.map((row, r) =>                           // assignment(6) + binding(1) + binding(1) + invocation(2) + binding(1) + binding(1)
    row.map((cell, c) => {                                    // invocation(2) + binding(1) + binding(1) + binding(1)
      const neighbors = countNeighbors(r, c);                 // assignment(6) + binding(1) + invocation(2) + binding(1) + binding(1)
      return cell ? neighbors === 2 || neighbors === 3 : neighbors === 3;  // conditional(4) + binding(1) + binding(1) + constant(1) + binding(1) + constant(1) + binding(1) + constant(1)
    })
  );

  const hasLiveCell = next.some(row => row.some(cell => cell));  // assignment(6) + binding(1) + invocation(2) + binding(1) + invocation(2) + binding(1) + invocation(2) + binding(1) + binding(1)
  return hasLiveCell ? next : [];                             // conditional(4) + binding(1) + binding(1) + constant(1)
}
